class Solution:
    def findMin(self, nums: List[int]) -> int:
        start = 0
        end = len(nums) - 1

        if(nums[start] <= nums[end]):
            return nums[0]

        while start <= end:
            mid = (start + end) // 2

            if(nums[mid] > nums[mid+1]):
                return nums[mid+1]

            if(nums[mid-1] > nums[mid]):
                return nums[mid]

            if(nums[mid] > nums[0]):
                start = mid + 1
            else:
                end = mid - 1

        return nums[start]

class Solution:
    def findMin(self, a: List[int]) -> int:

        def solve(l,h):
            while l<h:
                m=(l+h)//2

                if a[m]<a[m-1]:
                    return a[m]

                elif a[m]>a[h-1]:
                    l=m+1

                elif a[m]<a[h-1]:
                    h=m

                else:

                    if len(set(a[l:m+1]))==1:
                        return min(a[m],solve(m+1,h))

                    else:
                        return min(a[m],solve(l,m))

            return a[min(l,len(a)-1)]

        return solve(0,len(a))

