        L = []
        for idx, value in enumerate(s):
            if value == c:
                L.append(idx)

        distance = []
        i = 0
        for idx, value in enumerate(s):
            if value == c:
                distance.append(0)
                i += 1
            elif idx < L[0]:
                distance.append(L[0] - idx)
