        mx = -math.inf
        curr = -math.inf
        for i in range(1, len(arr)):
            if arr[i] > arr[i-1]:
                if increasing:
                    curr += 1
                    increased = True
                else:
                    mx = max(curr, mx)
                    curr = 2
                    increased = True
                    increasing = True
            elif arr[i] < arr[i-1]:
