class Solution:
    def shortestSubarray(self, nums: List[int], k: int) -> int:
        loc = {0: -1}
        stack = [0] # increasing stack
        ans, prefix = inf, 0
        for i, x in enumerate(nums): 
            prefix += x
            ii = bisect_right(stack, prefix - k)
            if ii: ans = min(ans, i - loc[stack[ii-1]])
            loc[prefix] = i
            while stack and stack[-1] >= prefix: stack.pop()
            stack.append(prefix)
        return ans if ans < inf else -1

class Solution:
    def distanceK(self, root: TreeNode, target: TreeNode, k: int) -> List[int]:

        graph=defaultdict(list)
        #create undirected graph
        stack=[root]
        while stack:
            node=stack.pop()
            if node==target:
                targetVal=node.val
            if node.left:
                graph[node.val].append(node.left.val)
                graph[node.left.val].append(node.val)
                stack.append(node.left)
            if node.right:
                graph[node.val].append(node.right.val)
                graph[node.right.val].append(node.val)
                stack.append(node.right)

        #start BFS
        q=deque([(targetVal,0)]) #startNode distance=0
        seen=set()
        seen.add(targetVal)
        res=[]
        while q:
            node,depth=q.popleft()
            if depth==k: 
                res.append(node)
            if depth>k: break #no need to continue

            for neigh in graph[node]:
                if neigh not in seen:
                    q.append((neigh,depth+1))
                    seen.add(neigh)
        return res

