        result = []
        while l<r:
            mid = (l+r)//2
            d = {}
            max_string = ""
            for i in range(length-mid):
                    if d.get(s[i:i+mid+1],0):
                        max_string = s[i:i+mid+1]
                        break
                    d[s[i:i+mid+1]] = 1
