            if text[i] not in first_occurence: first_occurence[text[i]] = i
            last_occurence[text[i]] = i

        for i in range(n+1):
            if i < n and text[i] == text[prev]:
                count += 1
            else:
                if first_occurence[text[prev]] < prev or last_occurence[text[prev]] > i : count += 1
                ans = max(ans,count)
                count = 1
                prev = i

