            ans = 0
            for i in range(1, 7):
                if i == prevNum:
                    if prevNumFreq < rollMax[i - 1]:
                        ans += func(idx + 1, i, prevNumFreq + 1)

                else:
                    ans += func(idx + 1, i, 1)

            return ans % MOD

        return func(0, 0, 0)

