            """Return number of substrings ending at s[i] and t[j] with k=0/1 difference."""
            if i < 0 or j < 0: return 0 
            if s[i] == t[j]: return fn(i-1, j-1, k) + (k==0)
            else: return 0 if k == 0 else 1 + fn(i-1, j-1, 0)

