        m, n = destination # m "V" &amp; n "H" in total 
        ans = ""
        while n: 
            kk = comb(m+n-1, n-1) # (m+n-1 choose n-1) instructions starting with "H"  
            if kk >= k: 
                ans += "H"
                n -= 1
            else: 
                ans += "V"
                m -= 1
                k -= kk 
        return ans + m*"V"

