        def recursive(s,ans):
            if len(s)>=low and len(s)<=high:
                ans+=[s]
            if len(s)>high:
                return 
            recursive(s+"0"*zero,ans)
            recursive(s+"1"*one,ans)
            return
        ans=[]
        recursive("",ans)
        return len(ans)

class Solution:
    def mostProfitablePath(self, edges: List[List[int]], bob: int, amount: List[int]) -> int:
        path_b = set([bob])
        lvl_b = {bob:0}
        g = defaultdict(list)
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        n = len(amount)
        node_lvl = [0] * n
        q = deque([0])

        lvl = 0
        seen = set([0])
        while q:
            size = len(q)
            for _ in range(size):
                u = q.popleft()
                node_lvl[u] = lvl
                for v in g[u]:
                    if v in seen:
                        continue
                    q.append(v)
                    seen.add(v)
            lvl += 1
        b = bob
        lvl = 1
        while b != 0:
            for v in g[b]:
                if node_lvl[v] > node_lvl[b]:
                    continue
                b = v
                cost = amount[b]
                path_b.add(b)
                lvl_b[b] = lvl
                break
            lvl += 1
        # print(f"lvl_b {lvl_b} path_b {path_b}  ")
        cost_a = []
        q = deque([(0, amount[0])])
        seen = set([0])
        lvl = 1
        while q:
            size = len(q)
            for _ in range(size):
                u, pre_cost = q.popleft()
                child_cnt = 0
                for v in g[u]:
                    if v in seen:
                        continue
                    seen.add(v)
                    child_cnt += 1
                    cost = pre_cost
                    inc = amount[v]
                    if v in path_b:
                        if lvl_b[v] == lvl:
                            cost += inc//2
                        elif lvl_b[v] > lvl:
                            cost += inc
                        else:
                            cost += 0
                    else:
                        cost += amount[v]
                    q.append((v, cost))
                if child_cnt == 0:
                    cost_a.append(pre_cost)
            lvl += 1
        ans = max(cost_a)
        return ans

class Solution:
    def splitMessage(self, message: str, limit: int) -> List[str]:
        def splitable_within(parts_limit):
            # check the message length achievable with <parts_limit> parts
            length = sum(limit - len(str(i)) - len(str(parts_limit)) - 3 for i in range(1, parts_limit + 1))
            return length >= len(message)

        parts_limit = 9
        if not splitable_within(parts_limit):
            parts_limit = 99
        if not splitable_within(parts_limit):
            parts_limit = 999
        if not splitable_within(parts_limit):
            parts_limit = 9999
        if not splitable_within(parts_limit):
            return []

        # generate the actual message parts
        parts = []
        m_index = 0  # message index
        for part_index in range(1, parts_limit + 1):
            if m_index >= len(message): break
            length = limit - len(str(part_index)) - len(str(parts_limit)) - 3
            parts.append(message[m_index:m_index + length])
            m_index += length

        return [f'{part}<{i + 1}/{len(parts)}>' for i, part in enumerate(parts)]

